  ('BNS','308','IPC 383/384 (extortion)'),
  ('BNS','309','IPC 390/392 (robbery)'),
  ('BNS','310','IPC 391/395 (dacoity)'),
  ('BNS','316','IPC 405/406 (criminal breach of trust)'),
  ('BNS','318','IPC 415/417/420 (cheating)'),
  ('BNS','319','IPC 416/419 (cheating by personation)'),
  ('BNS','336','IPC 463/465 (forgery)'),
  ('BNS','338','IPC 467 (forgery of valuable security/will)'),
  ('BNS','340','IPC 471 (using forged document as genuine)'),
  ('BNS','115','IPC 321/323 (voluntarily causing hurt)'),
  ('BNS','117','IPC 322/325 (voluntarily causing grievous hurt)'),
  ('BNS','131','IPC 350/351/352 (assault or criminal force)'),
  ('BNS','351','IPC 503/506 (criminal intimidation)'),
  ('BNS','330','IPC 442/445 (house-trespass / house-breaking)'),
  ('BNS','331','IPC 451/453/456/457 (punishment for house-breaking)'),
  ('BNSS','173','CrPC 154 (FIR in cognizable cases)'),
