-- ===========================================================================
-- DATASET EXPANSION (P1) — broader BNS/BNSS/BSA coverage so the classifier can
-- map a wider range of incident narratives. Same condensed/paraphrased style;
-- replace with verbatim bare-act text from indiacode.nic.in before real use.
-- ===========================================================================
INSERT INTO statute_chunks (code, section_no, heading, text, keywords) VALUES
-- --- offences against the human body --------------------------------------
('BNS', '101', 'Murder',
 'Culpable homicide is murder if the act by which death is caused is done with the intention of causing death, or with intention/knowledge as specified. Punishable with death or imprisonment for life, and fine.',
 'murder killed death intentionally stabbed shot strangled fatal deceased homicide deliberate premeditated weapon blood'),
('BNS', '103', 'Punishment for murder',
 'Whoever commits murder shall be punished with death or imprisonment for life and shall also be liable to fine; murder by a group of five or more on specified grounds (race, caste, sex, language) is covered by s.103(2).',
 'murder punishment death life imprisonment killed mob lynching group beaten to death'),
('BNS', '105', 'Punishment for culpable homicide not amounting to murder',
 'Whoever commits culpable homicide not amounting to murder is punishable with imprisonment for life, or up to ten years, and fine, where the act is done with intention; or up to ten years/fine where done with knowledge.',
 'culpable homicide not murder death sudden fight provocation without premeditation died injuries succumbed'),
('BNS', '109', 'Attempt to murder',
 'Whoever does any act with such intention or knowledge and under such circumstances that, if death were caused, the act would be murder, is guilty of attempt to murder. Punishable with imprisonment up to ten years and fine; life imprisonment if hurt is caused.',
 'attempt to murder tried to kill shot at stabbed fired attacked survived grievous injury jaan se maarne'),
('BNS', '137', 'Kidnapping',
 'Kidnapping is either from India or from lawful guardianship. Whoever takes or entices a minor (under 18 if female, under 18 if male per the section) or a person of unsound mind out of lawful guardianship without consent commits kidnapping. Punishable with imprisonment up to seven years and fine.',
 'kidnapping kidnapped abducted took away enticed minor child missing girl boy guardian without consent forcibly taken'),
('BNS', '140', 'Kidnapping or abduction for specified purposes (murder, ransom, etc.)',
 'Whoever kidnaps or abducts any person in order to murder, for ransom, to subject to grievous hurt/slavery, etc., is punishable with rigorous imprisonment up to ten years / life, and fine, as per the relevant sub-section.',
 'abduction ransom kidnapped for money demand extort hostage held captive confined beg slavery'),
('BNS', '64', 'Punishment for rape',
 'Whoever commits rape (as defined in s.63) shall be punished with rigorous imprisonment of not less than ten years, extendable to life, and fine; aggravated forms (by police officer, public servant, gang, on a minor) attract enhanced punishment.',
 'rape sexual assault forced intercourse without consent victim woman survivor molested raped aggravated'),
('BNS', '74', 'Assault or use of criminal force to woman with intent to outrage modesty',
 'Whoever assaults or uses criminal force to any woman intending to outrage, or knowing it likely to outrage, her modesty is punishable with imprisonment of one to five years and fine.',
 'outrage modesty molestation molested woman inappropriately touched groped criminal force assault eve teasing harassment'),
('BNS', '79', 'Word, gesture or act intended to insult modesty of a woman',
 'Whoever, intending to insult the modesty of a woman, utters any word, makes any sound/gesture, or exhibits any object intending it to be seen/heard by her, or intrudes upon her privacy, is punishable with simple imprisonment up to three years and fine.',
 'insult modesty woman obscene gesture word stalking privacy vulgar comment passed lewd'),
('BNS', '85', 'Husband or relative of husband subjecting a woman to cruelty',
 'Whoever, being the husband or the relative of the husband of a woman, subjects such woman to cruelty (harassment to coerce an unlawful dowry demand, or conduct driving her to suicide/grave injury) is punishable with imprisonment up to three years and fine.',
 'cruelty husband in-laws dowry harassment domestic violence beaten wife matrimonial demand taunted physical mental torture married woman sasural'),
('BNS', '80', 'Dowry death',
 'Where the death of a woman is caused by burns/bodily injury or occurs otherwise than under normal circumstances within seven years of marriage, and she was subjected to cruelty/harassment for dowry soon before death, it is dowry death. Punishable with imprisonment of not less than seven years up to life.',
 'dowry death bride burning married woman died seven years harassment cruelty unnatural death in-laws demand'),
('BNS', '69', 'Sexual intercourse by employing deceitful means',
 'Whoever, by deceitful means or by making a promise to marry without intention of fulfilling it, has sexual intercourse with a woman (not amounting to rape), is punishable with imprisonment up to ten years and fine.',
 'false promise marriage cheated sexual relationship deceit refused to marry breach promise woman'),
-- --- against property / cyber / public tranquillity ------------------------
('BNS', '324', 'Mischief',
 'Whoever with intent to cause, or knowing he is likely to cause, wrongful loss or damage to the public or any person, causes destruction of any property or any change diminishing its value/utility, commits mischief. Punishment graded by value/type of damage (e.g. s.324(2)-(5)).',
 'mischief damage damaged destroyed broke vandalism property loss vehicle smashed set fire crops public property'),
('BNS', '326', 'Mischief by fire or explosive (incl. damaging property)',
 'Mischief by fire or any explosive substance intending to cause, or knowing it likely to cause, damage is punishable with enhanced imprisonment depending on the property destroyed.',
 'arson fire burnt set ablaze explosive damaged building house shop vehicle torched'),
('BNS', '189', 'Unlawful assembly',
 'An assembly of five or more persons is unlawful if its common object is to commit an offence, resist law, criminal trespass, etc. Members are punishable; being armed with a deadly weapon is aggravated.',
 'unlawful assembly mob group five persons gathered crowd common object armed weapons sticks stones'),
('BNS', '191', 'Rioting',
 'Whenever force or violence is used by an unlawful assembly or any member in prosecution of the common object, every member is guilty of rioting. Punishable with imprisonment up to two years; rioting with a deadly weapon up to five years.',
 'rioting riot violence mob force stones pelting clash group fight weapons crowd damage'),
('BNS', '61', 'Criminal conspiracy',
 'When two or more persons agree to do, or cause to be done, an illegal act or a legal act by illegal means, such agreement is a criminal conspiracy. Punishable as for abetment / per the gravity of the offence conspired.',
 'conspiracy conspired agreement planned together plotted hatched plan group accused colluded'),
('BNS', '3', 'General explanations — common intention',
 'Where a criminal act is done by several persons in furtherance of the common intention of all, each is liable as if done by him alone (joint liability). Read with the specific charging section.',
 'common intention jointly together acted in furtherance several persons shared all accused'),
('BNS', '111', 'Organised crime',
 'Any continuing unlawful activity by a crime syndicate (e.g. kidnapping, extortion, contract killing, cyber-crime, trafficking) carried on as a member or on behalf of a syndicate is organised crime, punishable with severe imprisonment up to life and fine.',
 'organised crime syndicate gang racket continuing extortion contract killing cyber trafficking mafia network'),
('BNS', '112', 'Petty organised crime',
 'Petty organised crime (e.g. theft by gangs, snatching, pickpocketing, organised betting/cheating) by a group or gang causing general feeling of insecurity is punishable with imprisonment of one to seven years and fine.',
 'petty organised crime gang pickpocket snatching organised theft betting public insecurity group'),
('BNS', '152', 'Act endangering sovereignty, unity and integrity of India',
 'Whoever excites or attempts to excite secession, armed rebellion, subversive activities, or encourages feelings of separatist activities endangering the sovereignty, unity and integrity of India is punishable with imprisonment for life or up to seven years and fine.',
 'sedition sovereignty unity integrity secession rebellion subversive separatist anti-national'),
-- --- BNSS procedural ------------------------------------------------------
('BNSS', '35', 'When police may arrest without warrant',
 'A police officer may arrest without a warrant a person who commits a cognizable offence in his presence or against whom a reasonable complaint/credible information exists, subject to the safeguards (notice of appearance for offences punishable up to seven years).',
 'arrest without warrant cognizable offence police powers notice appearance safeguard reasonable'),
('BNSS', '37', 'Designated police officer / control room and arrest records',
 'The State shall designate a police officer in every district and police station to maintain information about arrested persons, and details of arrests shall be prominently displayed.',
 'arrest record control room designated officer details of arrested displayed information'),
('BNSS', '58', 'Person arrested to be produced before Magistrate within 24 hours',
 'No police officer shall detain an arrested person in custody for more than twenty-four hours (excluding journey time) without the special order of a Magistrate under s.187.',
 'twenty-four hours produced magistrate arrest custody detention limit'),
('BNSS', '176', 'Procedure for investigation',
 'An officer in charge of a police station may, on information of a cognizable offence, investigate the facts and circumstances; for offences punishable for seven years or more, forensic evidence must be collected and videographed at the scene.',
 'investigation procedure cognizable forensic crime scene videography evidence collected seven years'),
('BNSS', '183', 'Recording of confessions and statements by Magistrate',
 'A Magistrate may record any confession or statement made in the course of investigation; confessions must be recorded with due safeguards (voluntariness, warning).',
 'confession statement recorded magistrate 164 voluntary witness accused safeguard'),
('BNSS', '184', 'Medical examination of victim of rape',
 'Where rape/attempt is alleged, the victim shall be examined by a registered medical practitioner with consent, and the report forwarded; examination to be completed without delay.',
 'medical examination rape victim consent registered practitioner report mlc forensic'),
('BNSS', '230', 'Supply of copy of police report and documents to accused',
 'The Magistrate shall furnish to the accused, free of cost, a copy of the police report (charge-sheet), FIR, statements and documents relied upon, within fourteen days.',
 'copy chargesheet supplied accused fir statements documents fourteen days'),
-- --- BSA evidence ---------------------------------------------------------
('BSA', '2', 'Definitions — document and evidence include electronic',
 'Evidence includes statements and documents (including electronic and digital records) produced for inspection of the Court; the definitions extend documentary evidence to electronic records.',
 'evidence document definition electronic digital record statement court'),
('BSA', '57', 'Primary evidence',
 'Primary evidence means the document itself produced for inspection; where a document is created/stored electronically, each file is primary evidence.',
 'primary evidence original document electronic file inspection'),
('BSA', '58', 'Secondary evidence',
 'Secondary evidence includes certified copies, copies made by mechanical processes, and oral accounts of contents; admissible in specified circumstances.',
 'secondary evidence certified copy duplicate photocopy admissible'),
('BSA', '39', 'Opinion of experts',
 'When the Court has to form an opinion on a point of foreign law, science, art, handwriting, finger impressions or electronic/digital evidence, the opinions of persons specially skilled (experts) are relevant.',
 'expert opinion forensic handwriting fingerprint dna electronic digital examiner science relevant'),
('BSA', '160', 'Number of witnesses',
 'No particular number of witnesses is required for the proof of any fact; the Court may act on the testimony of a single reliable witness.',
 'number witnesses single witness sole testimony reliable proof'),
('BNS', '226', 'Attempt to commit suicide to compel/restrain public servant',
 'Whoever attempts to commit suicide with the intent to compel or restrain any public servant from discharging official duty is punishable with simple imprisonment up to one year, fine, community service, or all.',
 'attempt suicide compel public servant protest self harm threat'),
-- --- offences by/relating to public servants (corruption-adjacent) --------
('BNS', '198', 'Public servant disobeying law, with intent to cause injury',
 'Whoever, being a public servant, knowingly disobeys any direction of the law as to the way he is to conduct himself as such public servant, intending to cause, or knowing it likely that he will by such disobedience cause, injury to any person, is punishable with imprisonment up to one year, or fine, or both. Covers misuse of official position to harm a person.',
 'public servant official government officer abuse misuse of office position disobeyed law illegal demand harassment by official corruption bribe gratification withheld documents pending file'),
('BNS', '201', 'Public servant framing an incorrect document/record',
 'Whoever, being a public servant and charged with the preparation or translation of any document or electronic record, frames, prepares or translates it in a manner he knows or believes to be incorrect, intending or knowing it likely to cause injury, is punishable with imprisonment up to three years, or fine, or both.',
 'public servant official fabricated incorrect record document register entry tampered manipulated file false official record forged government'),
('BNS', '202', 'Public servant unlawfully engaging in trade or bidding for property',
 'Whoever, being a public servant, unlawfully engages in trade, or unlawfully buys or bids for certain property, contrary to the duties of his office, is punishable with imprisonment up to one year, or fine, or community service, or all.',
 'public servant official unlawful trade conflict of interest abuse office benefit personal gain corruption')
ON CONFLICT DO NOTHING;

-- Enrich extortion keywords so a bribe/illegal-gratification demand (withholding
-- an official act to induce payment) surfaces s.308 rather than the FIR section.
UPDATE statute_chunks
   SET keywords = keywords || ' bribe bribery illegal gratification corruption public servant official demanded money to release withhold rishvat lanch'
 WHERE code = 'BNS' AND section_no = '308';

-- Cross-refs for the public-servant offences (incl. special-law pointer).
UPDATE statute_chunks SET old_code_ref = m.ref FROM (VALUES
  ('BNS','198','IPC 166 (public servant disobeying law) · cf. Prevention of Corruption Act, 1988 s.7 for bribery'),
  ('BNS','201','IPC 167 (public servant framing incorrect record)'),
  ('BNS','202','IPC 168 (public servant unlawfully engaging in trade)')
) AS m(code, section_no, ref)
WHERE statute_chunks.code = m.code AND statute_chunks.section_no = m.section_no;

