INSERT INTO judgments_cache (indiankanoon_doc_id, title, summary, tags) VALUES
('IK-1000001', 'State of Gujarat v. Accused (theft of property)',
 'Conviction for theft from a dwelling; discusses dishonest intention and possession.',
 ARRAY['theft','dwelling','intention']),
('IK-1000002', 'State v. Accused (cheating and inducement)',
 'Discusses essentials of cheating: deception and dishonest inducement to deliver property.',
 ARRAY['cheating','fraud','inducement']),
('IK-1000003', 'In re Electronic Evidence Certificate',
 'Lays down that electronic records require a valid certificate for admissibility.',
 ARRAY['electronic evidence','certificate','admissibility']),
('IK-1000004', 'Anvar P.V. v. P.K. Basheer (2014) 10 SCC 473',
 'Landmark: electronic records are admissible only with a s.65B Evidence Act certificate (now BSA s.63); secondary electronic evidence without the certificate is inadmissible.',
 ARRAY['electronic evidence','certificate','admissibility','65B','BSA 63']),
('IK-1000005', 'Arjun Panditrao Khotkar v. Kailash Kushanrao Gorantyal (2020) 7 SCC 1',
 'Clarifies that the s.65B certificate is a mandatory condition precedent to admissibility of electronic records; addresses when the certificate can be produced.',
 ARRAY['electronic evidence','certificate','admissibility','mandatory']),
('IK-1000006', 'Arnesh Kumar v. State of Bihar (2014) 8 SCC 273',
